/**
 * ConfirmationModal - Displays order creation success confirmation with order ID
 * Shows order details and provides redirect option
 */

import { useEffect } from 'react'

interface ConfirmationModalProps {
  isOpen: boolean
  orderId: string
  onClose: () => void
}

export function ConfirmationModal({ isOpen, orderId, onClose }: ConfirmationModalProps) {
  // Auto-close after 3 seconds
  useEffect(() => {
    if (isOpen) {
      const timer = setTimeout(onClose, 3000)
      return () => clearTimeout(timer)
    }
  }, [isOpen, onClose])

  if (!isOpen) return null

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
      <div className="bg-white rounded-lg shadow-lg p-8 max-w-md w-full mx-4">
        {/* Success Icon */}
        <div className="flex justify-center mb-4">
          <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center">
            <svg
              className="w-8 h-8 text-green-600"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M5 13l4 4L19 7"
              />
            </svg>
          </div>
        </div>

        {/* Title */}
        <h2 className="text-2xl font-bold text-center text-gray-900 mb-2">Order Created!</h2>

        {/* Message */}
        <p className="text-center text-gray-600 mb-6">Your order has been successfully created.</p>

        {/* Order ID */}
        <div className="bg-gray-50 rounded-lg p-4 mb-6">
          <p className="text-sm text-gray-600 mb-1">Order ID</p>
          <p className="text-lg font-mono font-bold text-gray-900 break-all">{orderId}</p>
        </div>

        {/* Close Button */}
        <button
          onClick={onClose}
          className="w-full px-4 py-3 bg-[#ED0577] text-white rounded-lg font-medium hover:bg-[#d9066a] transition-colors min-h-[44px]"
        >
          Continue
        </button>

        {/* Auto-close message */}
        <p className="text-xs text-gray-500 text-center mt-4">Redirecting in 3 seconds...</p>
      </div>
    </div>
  )
}

export default ConfirmationModal
